import React from "react";

const ProblemSection = () => {
  return (
    <section style={{ display: "flex", maxWidth: "900px", margin: "0 auto 4rem", gap: "2rem", alignItems: "center" }}>
      <div style={{ flex: 1 }}>
        <h3 style={{ textTransform: "uppercase", color: "#00509e", marginBottom: "0.5rem" }}>
          The Problem
        </h3>
        <h2 style={{ fontWeight: "900", fontSize: "2rem", marginBottom: "1rem" }}>
          Dehydration, the hidden foe
        </h2>
        <p style={{ fontSize: "1rem", lineHeight: "1.5" }}>
          Everyday for both of us was plagued by classic burnout—frequent headaches, lack of focus, and low energy.
          Without knowing it, dehydration had reared its ugly head and controlled our every move. Gallons of water we
          chugged at our respective jobs couldn’t save us. We needed a new hero.
        </p>
      </div>
      <div style={{ flex: 1 }}>
        <img
          src="/media/aboutus/drinks_lineup.jpg"
          alt="Hydrant drink lineup"
          style={{ width: "100%", borderRadius: "1rem" }}
        />
      </div>
    </section>
  );
};

export default ProblemSection;
